1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	const PROCESSING_FEE = 5;
29	
30	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
31	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
32	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
33	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
34	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
35	
36	const sumBasePremiums = (items: Item[]): number =>
37	  items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
38	
39	export const quote = (
40	  _customer: Customer,
41	  step: QuoteStep,
42	  _quoteIndex: number,
43	): QuoteResult => {
44	  const basePremium = sumBasePremiums(step.items);
45	  const withFirstInsurance =
46	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
47	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
48	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
49	  return { premium };
50	};
51	
52	export const claim = (): unknown => {
53	  return undefined;
54	};
